import { ILeaveManagementService } from './leave-management.service.interface';
import { ILeaveRepository } from '../leave/leave.repository';
import { ILeavePolicyRepository } from '../policy/policy.repository';
import { IBalanceRepository } from '../balance/balance.repository';
import { IAuditLogRepository } from '../audit/audit.repository';
import { CreateLeaveRequestDto, LeaveRequest, LeaveRequestStatus } from '../leave/leave.model';
import { LeavePolicy } from '../policy/policy.model';
import { LeaveBalance } from '../balance/balance.model';
import { Pool, PoolClient } from '../../shared/db/connection';

export class LeaveManagementService implements ILeaveManagementService {
  constructor(
    private readonly leaveRepo: ILeaveRepository,
    private readonly policyRepo: ILeavePolicyRepository,
    private readonly balanceRepo: IBalanceRepository,
    private readonly auditRepo: IAuditLogRepository,
    private readonly dbPool: Pool
  ) {}

  async applyForLeave(dto: CreateLeaveRequestDto): Promise<LeaveRequest> {
    // Input validation
    if (!dto.employeeId || !dto.leaveTypeId || !dto.startDate || !dto.endDate) {
      throw new Error('Missing required fields');
    }
    if (new Date(dto.endDate) < new Date(dto.startDate)) {
      throw new Error('endDate must be on or after startDate');
    }

    // Validate leave policy
    const policy: LeavePolicy | null = await this.policyRepo.findByLeaveTypeId(dto.leaveTypeId);
    if (!policy) {
      throw new Error('Leave policy not found for the given leave type');
    }

    // Check balance
    const year = new Date(dto.startDate).getFullYear();
    const balance: LeaveBalance | null = await this.balanceRepo.findByEmployeeAndTypeAndYear(
      dto.employeeId,
      dto.leaveTypeId,
      year
    );
    if (!balance) {
      throw new Error('Leave balance not found');
    }
    const requestedDays = this.calculateDays(dto.startDate, dto.endDate);
    if (balance.totalEntitlement - balance.usedDays - balance.pendingDays < requestedDays) {
      throw new Error('Insufficient leave balance');
    }

    // Start transaction
    const client: PoolClient = await this.dbPool.connect();
    try {
      await client.query('BEGIN');

      // Create leave request with status draft
      const draftRequest = await this.leaveRepo.create(
        {
          employeeId: dto.employeeId,
          leaveTypeId: dto.leaveTypeId,
          startDate: dto.startDate,
          endDate: dto.endDate,
          status: LeaveRequestStatus.DRAFT,
          reason: dto.reason,
        },
        client
      );

      // Transition to submitted
      const submittedRequest = await this.leaveRepo.updateStatus(
        draftRequest.id,
        LeaveRequestStatus.SUBMITTED,
        client
      );

      // Audit log
      await this.auditRepo.create(
        {
          entityType: 'leave_request',
          entityId: submittedRequest.id,
          action: 'SUBMITTED',
          changedBy: dto.employeeId,
          newValues: { status: LeaveRequestStatus.SUBMITTED },
        },
        client
      );

      await client.query('COMMIT');
      return submittedRequest;
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }

  private calculateDays(start: string, end: string): number {
    const startDate = new Date(start);
    const endDate = new Date(end);
    const diffTime = endDate.getTime() - startDate.getTime();
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1;
  }
